from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper utilities
    def _format_date(date_str: str) -> str:
        """Convert YYYY-MM-DD to a readable format like 'January 20, 1930'."""
        date_str = date_str.strip('"')
        parts = date_str.split("-")
        if len(parts) == 3:
            year, month, day = parts
            months = {
                "01": "January", "02": "February", "03": "March", "04": "April",
                "05": "May", "06": "June", "07": "July", "08": "August",
                "09": "September", "10": "October", "11": "November", "12": "December",
            }
            month_name = months.get(month, month)
            return f"{month_name} {int(day)}, {year}"
        return date_str

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip('"')
        p = pred.lower()
        if p == "birthdate":
            return f"{subj} was born on {_format_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {_format_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            return f"{subj} was {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Use status as a preceding adjective when possible
            if obj.lower() in {"retired", "active", "deceased"}:
                return f"{obj.capitalize()} {subj}"
            return f"{subj} is {obj.lower()}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"{obj} operated {subj}"
        if p == "commander":
            return f"The commander of {subj} was {obj}"
        if p == "backuppilot":
            return f"The backup pilot of {subj} was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "fossil":
            return f"{obj} is a fossil found in {subj}"
        if p == "bird":
            return f"The {obj.lower()} is the state bird of {subj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        # Join parts with commas and a final conjunction
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        sentences.append(sent)

    # Combine subject sentences
    return " Also, ".join(sentences) + "."

# EVOLVE-BLOCK-END

